1	export type Cell = [number, number];
2	
3	const MIN_NEIGHBORS_TO_SURVIVE = 2;
4	const MAX_NEIGHBORS_TO_SURVIVE = 3;
5	
6	function isNeighbor(a: Cell, b: Cell): boolean {
7	  const [ax, ay] = a;
8	  const [bx, by] = b;
9	  return Math.max(Math.abs(ax - bx), Math.abs(ay - by)) === 1;
10	}
11	
12	function countLiveNeighbors(cell: Cell, cells: Cell[]): number {
13	  return cells.filter((other) => isNeighbor(cell, other)).length;
14	}
15	
16	function survives(cell: Cell, cells: Cell[]): boolean {
17	  const count = countLiveNeighbors(cell, cells);
18	  return count >= MIN_NEIGHBORS_TO_SURVIVE && count <= MAX_NEIGHBORS_TO_SURVIVE;
19	}
20	
21	export function nextGeneration(cells: Cell[]): Cell[] {
22	  return cells.filter((cell) => survives(cell, cells));
23	}
24

1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Game of Life - nextGeneration", () => {
5	  it("empty input returns empty array", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("single live cell dies (underpopulation) — [(0,0)] → []", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("two adjacent live cells both die (underpopulation, 1 neighbor each) — [(0,1),(1,1)] → []", () => {
12	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
13	  });
14	  it("live cell with 2 neighbors survives (rule 2 survival)", () => {
15	    // Horizontal row: (0,0), (1,0), (2,0). Middle cell (1,0) has 2 live neighbors → survives.
16	    const next = nextGeneration([[0, 0], [1, 0], [2, 0]]);
17	    expect(next).toContainEqual([1, 0]);
18	  });
19	  it("live cell with 3 neighbors survives (rule 2 survival) — block cell survives", () => {
20	    // Block: each cell has exactly 3 live neighbors → all survive
21	    const next = nextGeneration([[0, 0], [1, 0], [0, 1], [1, 1]]);
22	    expect(next).toContainEqual([0, 0]);
23	  });
24	  it("live cell with 4 neighbors dies (overpopulation)", () => {
25	    // Center (1,1) has 4 diagonal live neighbors: (0,0), (2,0), (0,2), (2,2)
26	    const next = nextGeneration([[0, 0], [2, 0], [1, 1], [0, 2], [2, 2]]);
27	    expect(next).not.toContainEqual([1, 1]);
28	  });
29	  it.todo("dead cell with exactly 3 live neighbors becomes alive (reproduction)");
30	  it.todo("block still life remains unchanged — [(0,0),(1,0),(0,1),(1,1)] → same");
31	  it.todo("vertical blinker becomes horizontal — [(0,0),(0,1),(0,2)] → [(-1,1),(0,1),(1,1)]");
32	  it.todo("handles negative coordinates correctly");
33	});
